 28→        private void StyleControls()
 29→        {
 30→            this.BackColor = pColor.Theme.backColor;
 31→
 32→            // 패널들 배경 흰색 적용
 33→            Panel[] panels = { panel2 };
 34→            foreach (var pnl in panels)
 35→                pnl.BackColor = pColor.Theme.panelColor;
 36→
 37→            // 버튼 스타일 통일화
 38→            foreach (var ctrl in panel2.Controls)
 39→            {
 40→                if (ctrl is Button btn)
 41→                {
 42→                    btn.BackColor = pColor.Theme.buttonColor;
 43→                    btn.ForeColor = pColor.Theme.buttonText;
 44→                    btn.FlatStyle = FlatStyle.Flat;
 45→                    btn.FlatAppearance.BorderSize = 0;
 46→                    // 둥근 모서리
 47→
 48→                    btn.Region = Region.FromHrgn(CreateRoundRectRgn(0, 0, btn.Width, btn.Height, 15, 15));
 49→
 50→                    // 호버 효과
 51→                    btn.MouseEnter += (s, e) => btn.BackColor = pColor.Theme.buttonHover;
 52→                    btn.MouseLeave += (s, e) => btn.BackColor = pColor.Theme.buttonColor;
 53→                }
 54→            }
 55→        }
 56→        private List<string> FindAllCsvFiles(DateTime startDate, DateTime endDate)
 57→        {
 58→            string baseDir = GlobalValues.GetDataPath();
 59→            List<string> resultFiles = new List<string>();
 60→
 61→            for (DateTime date = startDate; date <= endDate; date = date.AddDays(1))
 62→            {
 63→                string folder = Path.Combine(baseDir, date.ToString("yyyy"), date.ToString("MM"), date.ToString("dd"));
 64→                if (!Directory.Exists(folder)) continue;
 65→
 66→                string[] files = Directory.GetFiles(folder, "*.csv");
 67→                resultFiles.AddRange(files);
 68→            }
 69→
 70→            return resultFiles;
 71→        }
 72→        private DataTable LoadCsvDataToTable(List<string> files)
 73→        {
 74→            DataTable table = new DataTable();
 75→
 76→            bool headerRead = false;
 77→
 78→            foreach (var file in files)
 79→            {
 80→                using (StreamReader reader = new StreamReader(file, Encoding.UTF8))
 81→                {
 82→                    string headerLine = reader.ReadLine();
 83→                    if (headerLine == null) continue;
 84→
 85→                    string[] headers = headerLine.Split(',');
 86→
 87→                    if (!headerRead)
 88→                    {
 89→                        foreach (var h in headers)
 90→                            table.Columns.Add(h);
 91→                        headerRead = true;
 92→                    }
 93→
 94→                    while (!reader.EndOfStream)
 95→                    {
 96→                        string line = reader.ReadLine();
 97→                        if (string.IsNullOrWhiteSpace(line)) continue;
 98→
 99→                        string[] values = line.Split(',');
100→                        table.Rows.Add(values);
